import fs from 'fs';
let css = fs.readFileSync\('src/index.css', 'utf8'\);

const replacements = [
  ['var\(--red\)', 'var\(--up\)'],
  ['var\(--green\)', 'var\(--down\)'],
  ['var\(--blue\)', 'var\(--info\)'],
  ['var\(--cyan\)', 'var\(--accent\)'],
  ['var\(--gold\)', 'var\(--warn\)'],
  ['var\(--red-bg\)', 'var\(--up-bg\)'],
  ['var\(--green-bg\)', 'var\(--down-bg\)'],
  ['var\(--blue-bg\)', 'var\(--info-bg\)'],
  ['var\(--cyan-bg\)', 'var\(--accent-bg\)'],
  ['var\(--gold-bg\)', 'var\(--warn-bg\)'],
  ['var\(--border-light\)', 'var\(--border-strong\)'],
];

let totalReplaced = 0;
for \(const [old, rep] of replacements\) {
  const count = css.split\(old\).length - 1;
  if \(count > 0\) {
    css = css.split\(old\).join\(rep\);
    totalReplaced += count;
    console.log\(old + ' -> ' + rep + ': ' + count\);
  }
}

// var\(--border\) -> var\(--border-default\) using negative lookahead
const borderRegex = new RegExp\('var\\\\\\\\\(--border\\\\\\\\\)\(?![\\\\\\\\w-]\)', 'g'\);
const borderMatches = \(css.match\(borderRegex\) || []\).length;
css = css.replace\(borderRegex, 'var\(--border-default\)'\);
console.log\('var\(--border\) -> var\(--border-default\): ' + borderMatches\);
totalReplaced += borderMatches;

console.log\('Total: ' + totalReplaced\);
fs.writeFileSync\('src/index.css', css\);
")

