var fs = require\('fs'\);
var css = fs.readFileSync\('src/index.css', 'utf8'\);
// Simple approach: split on 'var\(--border\)' but rejoin with care for --border-default/strong
// Since --border-light already replaced to --border-strong, only bare var\(--border\) remain
// Check if followed by a dash \(part of longer token name\)
var parts = css.split\('var\(--border\)'\);
var count = 0;
var result = parts[0];
for \(var i = 1; i < parts.length; i++\) {
  if \(parts[i].charAt\(0\) === '-'\) {
    // This is var\(--border-something\), keep original
    result += 'var\(--border\)' + parts[i];
  } else {
    result += 'var\(--border-default\)' + parts[i];
    count++;
  }
}
console.log\('Replaced: ' + count\);
fs.writeFileSync\('src/index.css', result\);
")
